import React from 'react';
import './Tiles.css';

class Tiles extends React.Component {

  render() {
      const { children, heading } = this.props;

      return (
          <section aria-label={heading} className="tile__outer-container">
              <header className="tile__header">
                  <img src="images/logo.png" alt="Channel 7 logo" className="tile__logo" />
                  <h1 className="tile__heading">{heading}</h1>
              </header>
              <div className="tile__inner-container">
                  {children}
              </div>
          </section>
      )
  }
}

export default Tiles;